module top_module(
    input [3:0] A,
    input [3:0] B,
    output [7:0] product
);wire [7:0] temp_product;

    wire negated_temp_product = A * B;
    assign temp_product = negated_temp_product;
    assign product[7:4] = temp_product[7:4];
    assign product[3:0] = temp_product[3:0];

endmodule
